import type {
  SentrySpanOptions,
  SentrySpanRecordOptions,
} from "@/decorator/sentry-span";

export type {
  SentrySpanAttributes,
  SpanAttributesResolver,
  SpanNameResolver,
} from "@/decorator/sentry-span";

/**
 * Wrap work in a Sentry span (renderer / webview).
 *
 * This module is used by the shared webview bundle (Electron + VS Code extension).
 * - VS Code extension: this base implementation is a no-op (extension must not depend on Sentry).
 * - Electron: `sentry-tracing.electron.ts` is selected via platform module resolution and uses
 *   `@sentry/browser` to create spans.
 *
 * Use this for renderer-side spans like `codex.user_action` and `codex.mcp.request`.
 */
export function withSentrySpan<T>(
  _options: SentrySpanOptions,
  callback: () => T,
): T {
  return callback();
}

export function recordSentrySpan(_options: SentrySpanRecordOptions): void {
  // No-op outside of the Electron renderer.
}
